import re

def title_words(s):
    words = s.split()
    title_cased_words = []
    for word in words:
        if word.isupper():
            title_cased_words.append(word)
        else:
            title_cased_words.append(word.title())
    return ' '.join(title_cased_words)

# Edge case: Single uppercase word
assert title_words('ABC') == 'ABC'
